import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secretFile.txt";

        // Validate user input to prevent directory traversal
        if (!userInput.contains("..") && !userInput.contains("/")) {
            String filePath = "/path/to/directory/" + userInput;

            try {
                File file = new File(filePath);
                FileInputStream fis = new FileInputStream(file);

                int data;
                while ((data = fis.read()) != -1) {
                    System.out.print((char) data);
                }

                fis.close();
            } catch (IOException e) {
                System.err.println("Error reading file: " + e.getMessage());
            }
        } else {
            System.err.println("Invalid file path specified.");
        }
    }
}

